import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Users, CreditCard, Gift, TrendingUp, Activity } from 'lucide-react';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalUsuarios: 0,
    usuariosAtivos: 0,
    totalGiftCards: 0,
    giftCardsUsados: 0,
    receitaMes: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadStats();
  }, []);

  const loadStats = async () => {
    try {
      // Carregar estatísticas do backend
      const [usuariosResponse, giftCardsResponse] = await Promise.all([
        axios.get('/api/admin/stats/usuarios'),
        axios.get('/api/admin/stats/giftcards')
      ]);

      setStats({
        totalUsuarios: usuariosResponse.data.total || 0,
        usuariosAtivos: usuariosResponse.data.ativos || 0,
        totalGiftCards: giftCardsResponse.data.total || 0,
        giftCardsUsados: giftCardsResponse.data.usados || 0,
        receitaMes: usuariosResponse.data.receitaMes || 0
      });
    } catch (error) {
      console.error('Erro ao carregar estatísticas:', error);
    } finally {
      setLoading(false);
    }
  };

  const statCards = [
    {
      title: 'Total de Usuários',
      value: stats.totalUsuarios,
      icon: Users,
      color: 'bg-blue-500',
      change: '+12%',
      changeType: 'positive'
    },
    {
      title: 'Usuários Ativos',
      value: stats.usuariosAtivos,
      icon: Activity,
      color: 'bg-green-500',
      change: '+8%',
      changeType: 'positive'
    },
    {
      title: 'Gift Cards Criados',
      value: stats.totalGiftCards,
      icon: Gift,
      color: 'bg-purple-500',
      change: '+25%',
      changeType: 'positive'
    },
    {
      title: 'Receita Mensal',
      value: `R$ ${stats.receitaMes.toFixed(2)}`,
      icon: TrendingUp,
      color: 'bg-yellow-500',
      change: '+15%',
      changeType: 'positive'
    }
  ];

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  return (
    <div>
      <div className="mb-8">
        <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
        <p className="text-gray-600">Visão geral do sistema</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {statCards.map((stat, index) => {
          const Icon = stat.icon;
          return (
            <div key={index} className="bg-white rounded-lg shadow p-6">
              <div className="flex items-center">
                <div className={`${stat.color} rounded-lg p-3`}>
                  <Icon className="h-6 w-6 text-white" />
                </div>
                <div className="ml-4">
                  <p className="text-sm font-medium text-gray-600">{stat.title}</p>
                  <p className="text-2xl font-bold text-gray-900">{stat.value}</p>
                  <div className="flex items-center mt-1">
                    <span className={`text-sm font-medium ${
                      stat.changeType === 'positive' ? 'text-green-600' : 'text-red-600'
                    }`}>
                      {stat.change}
                    </span>
                    <span className="text-sm text-gray-500 ml-1">vs mês anterior</span>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Quick Actions */}
      <div className="bg-white rounded-lg shadow p-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Ações Rápidas</h2>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <button className="flex items-center justify-center px-4 py-3 bg-primary-600 text-white rounded-lg hover:bg-primary-700 transition-colors">
            <Users className="h-5 w-5 mr-2" />
            Novo Usuário
          </button>
          <button className="flex items-center justify-center px-4 py-3 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors">
            <Gift className="h-5 w-5 mr-2" />
            Criar Gift Cards
          </button>
          <button className="flex items-center justify-center px-4 py-3 bg-purple-600 text-white rounded-lg hover:bg-purple-700 transition-colors">
            <CreditCard className="h-5 w-5 mr-2" />
            Ver Pagamentos
          </button>
        </div>
      </div>

      {/* Recent Activity */}
      <div className="mt-8 bg-white rounded-lg shadow p-6">
        <h2 className="text-lg font-semibold text-gray-900 mb-4">Atividade Recente</h2>
        <div className="space-y-4">
          <div className="flex items-center justify-between py-3 border-b">
            <div className="flex items-center">
              <div className="bg-blue-100 rounded-full p-2">
                <Users className="h-4 w-4 text-blue-600" />
              </div>
              <div className="ml-3">
                <p className="text-sm font-medium text-gray-900">Novo usuário cadastrado</p>
                <p className="text-sm text-gray-500">joao@exemplo.com</p>
              </div>
            </div>
            <span className="text-sm text-gray-500">Há 5 minutos</span>
          </div>
          <div className="flex items-center justify-between py-3 border-b">
            <div className="flex items-center">
              <div className="bg-green-100 rounded-full p-2">
                <Gift className="h-4 w-4 text-green-600" />
              </div>
              <div className="ml-3">
                <p className="text-sm font-medium text-gray-900">Gift Card resgatado</p>
                <p className="text-sm text-gray-500">GC-ABC12345</p>
              </div>
            </div>
            <span className="text-sm text-gray-500">Há 15 minutos</span>
          </div>
          <div className="flex items-center justify-between py-3">
            <div className="flex items-center">
              <div className="bg-purple-100 rounded-full p-2">
                <CreditCard className="h-4 w-4 text-purple-600" />
              </div>
              <div className="ml-3">
                <p className="text-sm font-medium text-gray-900">Pagamento confirmado</p>
                <p className="text-sm text-gray-500">R$ 29,90</p>
              </div>
            </div>
            <span className="text-sm text-gray-500">Há 1 hora</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
